import{_ as i,o as e,c as l,f as t}from"./app-55c326ac.js";const s={},a=t('<h1 id="系统服务启动文件" tabindex="-1"><a class="header-anchor" href="#系统服务启动文件" aria-hidden="true">#</a> 系统服务启动文件</h1><h2 id="xxx-service" tabindex="-1"><a class="header-anchor" href="#xxx-service" aria-hidden="true">#</a> xxx.service</h2><p>在centos7中，将一个安装的服务添加到启动中，并用sustemctl进行管理，需要编辑脚本服务文件，并将文件放在特定的位置并命名：</p><ul><li><p>位置及命名：<code>/usr/lib/systemd/system/xxx.service</code></p></li><li><p>service文件中的选项一般有:</p><ul><li>[unit]：定义与Unit类型无关的通用选项。用于提供unit的描述信息，unit行为及依赖关系</li><li>[Service]：与特定类型相关的专用现象，此处为service类型</li><li>[Install]：定义有“systemctl enable”以及”systemctl disable“命令在实现服务启动或禁止时用到的一些选项</li></ul></li></ul><h3 id="unit部分" tabindex="-1"><a class="header-anchor" href="#unit部分" aria-hidden="true">#</a> Unit部分</h3><p>常用选项：</p><ul><li>Description：描述信息</li><li>After：定义unit的启动次序，表示当前unit，应该晚于哪些unit启动，功能与before相反</li><li>Requires：依赖到其他的units，强依赖，被依赖的unit没有激活，当前的unit也不能正常启动</li><li>Wants：依赖到其他的unti，弱依赖</li><li>Conflicts：定义units</li></ul><h3 id="service部分" tabindex="-1"><a class="header-anchor" href="#service部分" aria-hidden="true">#</a> Service部分</h3><p>常用选项：</p><ul><li>Type：定义影响Execstart及相关参数的功能unit进程启动类型 <ul><li>simple：默认值，主要由：Execstart接的指令串来启动，启动后常住与内存中</li><li>forking：有ExecStart启动额程序透过spawns延伸出其他子程序来作为此daemon的主要服务。原父程序在启动结束后终止</li><li>oneshot：与simple类似，程序在工作完毕后结束，不会常驻内存</li><li>dbus：与simple类似，但这个daemon必须要在取得一个D-Bus的名称后，才会继续运行。因此通常需要同时设置<code>BusName=xxx</code>才可以。</li><li>notify：在启动完成后发送通知消息，需要配合NotifyAccess让systemd接收消息</li><li>idle：与simple类似，要执行这个daemon必须要所有的工作都顺利执行完毕后才会执行。这类的daemon通常是开机到最后才执行即可的服务</li></ul></li><li>EnvironmentFile：环境配置文件</li><li>ExecStart：指明启动服务要运行命令（命令+参数）或脚本的<code>绝对路径</code>，如果在命令前面加上下面的标志，将会有不同含义： <ul><li>@：表示后面的参数一次传递给被执行的程序</li><li>-：表示即使该进程以失败状态退出，也会被视为成功退出</li><li>+：表示该进程拥有超级用户特权</li><li>如果设置多个ExecStart=那么将依次运行，如果某个没有“-”前缀的命令执行失败，那么后续的ExecStart=将不会执行，同时该单元变为失败（failed）状态。</li><li>如果没有设置Type=forking时，这里的命令所启动的进程，将被视为该服务的主守护进程。</li></ul></li><li>ExecStartPre：ExecStart前运行</li><li>ExecStartPost：ExecStart后运行</li><li>ExecStop：知名停止unit要运行的命令或脚本</li><li>Restart：当设定Restart=1时，则当次daemon服务意外终止后，会再次自启动此服务</li><li>ReaminAfterExit：当前服务的所有进程都退出之后，是否依然将此无视为活动的，默认是：no</li><li>GuessMainPID：当没有设置PIDFile=值的时候，systemd是否要猜测主进程的PID。默认是：yes</li><li>PIDFile：守护京城的PID，也是绝对路径。建议在<code>Type=forking</code>的情况下明确设置<code>PIDFile</code></li><li>BusName：设置此服务通讯所使用的的D-Bus名称，当<code>Type=dbus</code>，必须设置<code>此项</code></li></ul><h3 id="install部分" tabindex="-1"><a class="header-anchor" href="#install部分" aria-hidden="true">#</a> Install部分</h3><p>常用选项：</p><ul><li>Alias：别名，可使用systemctl command Alias.service</li><li>RequiredBy：被哪些units所依赖，强依赖</li><li>WantedBy：被哪些units所依赖，弱依赖</li><li>Also：安装本服务的时候还需要安装别的相关服务</li></ul><blockquote><p>对于新创建的unit文件，或者修改了的unit文件，要通知systemd重新加载此配置文件，而后可以选择重启 <code>systemctl daemon-relaod</code>（重载所有修改过的配置文件）</p></blockquote>',14),n=[a];function c(r,d){return e(),l("div",null,n)}const u=i(s,[["render",c],["__file","Linux-系统服务启动文件.html.vue"]]);export{u as default};
